import{_ as s,o as n,c as i,ag as e}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"wf-init - 初始化项目","description":"","frontmatter":{},"headers":[],"relativePath":"skills/wf-init.md","filePath":"skills/wf-init.md"}'),l={name:"skills/wf-init.md"};function t(o,a,p,c,d,r){return n(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="wf-init-初始化项目" tabindex="-1">wf-init - 初始化项目 <a class="header-anchor" href="#wf-init-初始化项目" aria-label="Permalink to &quot;wf-init - 初始化项目&quot;">​</a></h1><p>初始化 WikiFlow 项目，在用户项目中创建文档驱动的开发环境。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 初始化当前项目</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/wf-init</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 初始化指定项目</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/wf-init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/project</span></span></code></pre></div><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><h3 id="_1-对话确认配置" tabindex="-1">1. 对话确认配置 <a class="header-anchor" href="#_1-对话确认配置" aria-label="Permalink to &quot;1. 对话确认配置&quot;">​</a></h3><p>向用户询问以下信息：</p><ul><li><strong>Q</strong>: 项目名称是什么？</li><li><strong>Q</strong>: 代码在哪个目录？（如 <code>src/</code>、<code>lib/</code>、<code>app/</code>）→ 用于 AI 定位代码</li><li><strong>Q</strong>: 主要编程语言是什么？</li><li><strong>Q</strong>: 工作流使用什么语言？（默认 <code>zh-CN</code>）</li><li><strong>Q</strong>: 文档放在哪个目录？（默认 <code>docs/</code>）</li></ul><h3 id="_2-检查现有目录" tabindex="-1">2. 检查现有目录 <a class="header-anchor" href="#_2-检查现有目录" aria-label="Permalink to &quot;2. 检查现有目录&quot;">​</a></h3><p>检查项目根目录下是否已有 <code>docs</code> 目录：</p><ul><li><strong>不存在</strong>：直接创建</li><li><strong>已存在</strong>：询问用户选择处理方式</li></ul><h3 id="_3-创建目录结构" tabindex="-1">3. 创建目录结构 <a class="header-anchor" href="#_3-创建目录结构" aria-label="Permalink to &quot;3. 创建目录结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{docs}/</span></span>
<span class="line"><span>├── wiki/</span></span>
<span class="line"><span>│   ├── current/          ← 当前实现（AI 查询优先读这里）</span></span>
<span class="line"><span>│   ├── history/          ← 历史版本</span></span>
<span class="line"><span>│   ├── deprecated/       ← 已废弃功能</span></span>
<span class="line"><span>│   ├── decisions/        ← 决策日志</span></span>
<span class="line"><span>│   ├── index.md          ← 主索引</span></span>
<span class="line"><span>│   └── log.md            ← 变更日志</span></span>
<span class="line"><span>├── raw/</span></span>
<span class="line"><span>│   └── 00-uncategorized/ ← 原始文档</span></span>
<span class="line"><span>└── changes/</span></span>
<span class="line"><span>    └── active/           ← 开发中的变更</span></span></code></pre></div><h3 id="_4-生成配置文件" tabindex="-1">4. 生成配置文件 <a class="header-anchor" href="#_4-生成配置文件" aria-label="Permalink to &quot;4. 生成配置文件&quot;">​</a></h3><ul><li><code>index.md</code> - Wiki 主索引</li><li><code>log.md</code> - 变更日志</li><li><code>.wikiflow/config.json</code> - 项目配置</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>如果用户项目已有文档，建议先放入 <code>raw/</code> 目录，后续通过工作流整理</li><li><code>project.code</code> 是面向 AI 的配置，用户无需关心代码细节</li><li><code>config.json</code> 可随时手动编辑，修改后立即生效</li><li>重复执行 <code>/wf-init</code> 会检测到已有配置，询问是否覆盖</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>初始化完成后，可以使用：</p><ul><li><code>/wf-plan &quot;功能描述&quot;</code> - 开始规划新功能</li><li><code>/wf-search &quot;关键词&quot;</code> - 查询现有文档</li></ul>`,20)])])}const g=s(l,[["render",t]]);export{u as __pageData,g as default};
